			const contentWidth = larghezza || boundingClientRect.width;

			const contentHeight = altezza || larghezza del contenuto * 0,5625;

			content.style.height = contentHeight + 'px';
			content.style.width = contentWidth + 'px';

			window.scrollTo(scrollPosition);
		}
		cattura (errore) {
			window.removeEventListener('ridimensiona', ridimensiona);
		}
	});
}

funzione mostraVideo() {
	videoContainer.removeAttribute('aria-hidden');
	errorMessage.parentElement.removeChild(errorMessage);
	loadIndicator.parentElement.removeChild(loadingIndicator);

	if (layoutMode!== 'modifica') {
		videoMask.parentElement.removeChild(videoMask);
	}

	window.addEventListener('ridimensiona', ridimensiona);

	ridimensiona();
}

funzione mostraErrore() {
	if (layoutMode === 'modifica') {
		errorMessage.removeAttribute('nascosto');
		videoContainer.parentElement.removeChild(videoContainer);
		loadIndicator.parentElement.removeChild(loadingIndicator);
	}
	altrimenti {
		frammentoElemento.parentElement.removeChild(frammentoElemento);
	}
}

const rawProvider = {
	getParametri: funzione (url) {
		ritorno {url:url};
	},

	showVideo: funzione (parametri) {
		const video = document.createElement('video');
		const source = document.createElement('source');

		sorgente.src = parametri.url;

		video.autoplay = configurazione.autoPlay;
		video.controls = !configuration.hideControls;
		video.loop = configurazione.loop;
		video.muted = configurazione.mute;

		video.style.height = '100%';
		video.style.width = '100%';

		video.appendChild(fonte);
		videoContainer.appendChild(video);
		mostraVideo();
	},
};

constProvideryoutube = {
	getParametri: funzione (url) {
		const inizio = url.searchParams.get('inizio');

		if (['www.youtube.com', 'youtube.com'].includes(url.nomehost)) {
			const videoId = url.searchParams.get('v');

			se (ID video) {
				ritorno {
					inizio: inizio,
					ID video: ID video,
				};
			}
		}
		else if (['www.youtu.be', 'youtu.be'].includes(url.hostname)) {
			const videoId = url.nomepercorso.substr(1);

			se (ID video) {
				ritorno {
					inizio: inizio,
					ID video: ID video,
				};
			}
		}
	},

	showVideo: funzione (parametri) {
		const handleAPIReady = funzione () {
			const player = nuovo YT.Player(videoContainer, {
				eventi: {
					onReady:funzione() {
						se (configurazione.mute) {
							giocatore.muto();
						}

						mostraVideo();
					},
				},
				altezza: altezza,
				playerVar: {
					riproduzione automatica: configurazione.autoPlay,
					controlli: configurazione.hideControls ? 0:1,
					ciclo: configurazione.ciclo ? 1:0,
					playlist: configurazione.loop
						? parametri.videoId
						: indefinito,
					inizio: !parametri.inizio ? 0: parametri.inizio,
				},
				ID video: parametri.ID video,
				larghezza:larghezza,
			});
		};

		if ('YT' nella finestra) {
			handleAPIReady();
		}
		altrimenti {
			const oldCallback =
				window.onYouTubeIframeAPIReady || funzione () {};

			window.onYouTubeIframeAPIReady = funzione () {
				vecchiaCallback();
				handleAPIReady();
			};

			const apiSrc = '//www.youtube.com/iframe_api';

			let script = Array.from(document.querySelectorAll('script')).find(
				funzione (copione) {
					return script.src === apiSrc;
				}
			);

			se (!script) {
				script = document.createElement('script');
				script.src = apiSrc;
				document.body.appendChild(script);
			}
		}
	},
};

funzione principale() {
	contenuto = frammentoElement.querySelector('.video');

	if (!contenuto) {
		richiesta di ritornoAnimationFrame(principale);
	}

	videoContainer = content.querySelector('.video-container');
	errorMessage = content.querySelector('.error-message');
	loadIndicator = content.querySelector('.loading-animation');
	videoMask = content.querySelector('.video-mask');

	window.removeEventListener('ridimensiona', ridimensiona);

	Liferay.on('tabsFragment:activePanel', (evento) => {
		if (event.panel && event.panel.contains(fragmentElement)) {
			ridimensiona();
		}
	});

	prova {
		lascia che corrisponda = falso;
		const url = nuovo URL(configuration.url, window.location.origin);
		fornitori const = [youtubeProvider, rawProvider];

		for (let i = 0; i < provider.lunghezza && !matched; i++) {
			const fornitore = fornitori[i];
			parametri const = provider.getParameters(url);

			se (parametri) {
				provider.showVideo(parametri);
				abbinato = vero;
			}
		}

		se (!corrispondente) {
			mostraErrore();
		}
	}
	cattura (errore) {
		mostraErrore();
	}
}

